     2|import Foundation
     3|import SwiftUI
     4|
     5|@MainActor
     6|final class MinifyViewModel: ObservableObject {
     7|    @Published var images: [InputImage] = []
     8|    @Published var outputFormat: OutputFormat = .webp
     9|    @Published var quality: Double = 0.72
    10|    @Published var estimatedSize: Int64 = 0
    11|    @Published var conversionResults: [ConversionResult] = []
    12|    @Published var isConverting = false
    13|    @Published var statusMessage: String = "Drop or pick images to begin."
    14|    @Published var lastError: String?
    15|
    16|    private let service = ImageConversionService()
    17|
    18|    func pickImages() {
    19|        let panel = NSOpenPanel()
    20|        panel.canChooseFiles = true
    21|        panel.canChooseDirectories = false
    22|        panel.allowsMultipleSelection = true
    23|        panel.allowedContentTypes = [.image]
    24|
    25|        if panel.runModal() == .OK {
    26|            addImageURLs(panel.urls)
    27|        }
    28|    }
    29|
    30|    func clearImages() {
    31|        images.removeAll()
    32|        conversionResults.removeAll()
    33|        recalculateEstimate()
    34|        statusMessage = "Selection cleared."
    35|    }
    36|
    37|    func addImageURLs(_ urls: [URL]) {
    38|        let fresh = urls.compactMap { url -> InputImage? in
    39|            guard let attrs = try? FileManager.default.attributesOfItem(atPath: url.path),
    40|                  let size = (attrs[.size] as? NSNumber)?.int64Value else { return nil }
    41|            return InputImage(url: url, byteCount: size)
    42|        }
    43|
    44|        var map: [String: InputImage] = [:]
    45|        for item in images + fresh {
    46|            map[item.url.path] = item
    47|        }
    48|        images = map.values.sorted { $0.url.lastPathComponent < $1.url.lastPathComponent }
    49|        recalculateEstimate()
    50|        statusMessage = "Loaded \(images.count) image(s)."
    51|    }
    52|
    53|    func recalculateEstimate() {
    54|        estimatedSize = service.estimateOutputBytes(for: images, format: outputFormat, quality: quality)
    55|    }
    56|
    57|    func convertAll() {
    58|        guard !images.isEmpty else {
    59|            statusMessage = "Select at least one image first."
    60|            return
    61|        }
    62|
    63|        let panel = NSOpenPanel()
    64|        panel.canChooseFiles = false
    65|        panel.canChooseDirectories = true
    66|        panel.canCreateDirectories = true
    67|        panel.prompt = "Choose Output Folder"
    68|
    69|        guard panel.runModal() == .OK, let folder = panel.url else { return }
    70|
    71|        isConverting = true
    72|        lastError = nil
    73|        statusMessage = "Converting \(images.count) image(s)..."
    74|
    75|        Task {
    76|            do {
    77|                let results = try service.convert(images: images, format: outputFormat, quality: quality, outputFolder: folder)
    78|                conversionResults = results
    79|                let totalIn = results.reduce(Int64(0)) { $0 + $1.originalBytes }
    80|                let totalOut = results.reduce(Int64(0)) { $0 + $1.outputBytes }
    81|                statusMessage = "Done. \(ByteCountFormatter.string(fromByteCount: totalIn, countStyle: .file)) → \(ByteCountFormatter.string(fromByteCount: totalOut, countStyle: .file))"
    82|            } catch {
    83|                lastError = error.localizedDescription
    84|                statusMessage = "Conversion failed."
    85|            }
    86|            isConverting = false
    87|        }
    88|    }
