    private func uniqueDestinationURL(for baseURL: URL) -> URL {
        let fm = FileManager.default
        if !fm.fileExists(atPath: baseURL.path) {
            return baseURL
        }

        let stem = baseURL.deletingPathExtension().lastPathComponent
        let ext = baseURL.pathExtension
        let parent = baseURL.deletingLastPathComponent()

        var index = 2
        while true {
            let candidate = parent.appendingPathComponent("\(stem)-\(index)").appendingPathExtension(ext)
            if !fm.fileExists(atPath: candidate.path) {
                return candidate
            }
            index += 1
        }
    }
